code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double s, v;
        scanf("%lf %lf", &s, &v);
        double time = s / (v * sqrt(3.0) / 3.0);
        printf("%.6f\n", time);
    }
    return 0;
}

