code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            double s = sc.nextDouble();
            double v = sc.nextDouble();
            double time = s / (v * Math.sqrt(3.0) / 3.0);
            System.out.printf("%.6f\n", time);
        }
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [s, v] = readline().split(' ').map(Number);
    const time = s / (v * Math.sqrt(3.0) / 3.0);
    console.log(time.toFixed(6));
}
